"""wecomagent._rpc：TCP NDJSON 客户端。

协议：
1. 连接 `WECOMAGENT_RPC_HOST:WECOMAGENT_RPC_PORT`（Rust 端 bind 127.0.0.1:0 得到）
2. 发握手：``{"type":"hello","token":<WECOMAGENT_RPC_TOKEN>}\n``
3. 读握手响应：``{"type":"welcome","server_version":"pr3"}\n``
4. 之后每次 ``call(method, params)`` 发一行 ``{"id":N,"method":...,"params":...}``，
   读一行 ``{"id":N,"result":...}`` 或 ``{"id":N,"error":{"code":...,"message":...}}``

当前 Rust 侧（`runtime/python_host/dispatch.rs`）只路由 `wecom.exec` 一个 method，
其它 method 会以 ``-32601 MethodNotFound`` 返回。后续 PR 再扩 `memory.*` / `llm.chat` /
`session.*` / `log.emit`。

连接懒建立，首次 ``call`` 才握手；之后常驻复用。多线程并发下用 ``threading.Lock``
串行化，避免交错帧。进程退出时靠 socket close 自然回收（Rust 侧 shutdown 会先到）。
"""

from __future__ import annotations

import json
import os
import socket
import threading
from typing import Any, Optional

from .errors import RpcError


# Rust 端通过环境变量注入的 endpoint 三元组。
ENV_RPC_HOST = "WECOMAGENT_RPC_HOST"
ENV_RPC_PORT = "WECOMAGENT_RPC_PORT"
ENV_RPC_TOKEN = "WECOMAGENT_RPC_TOKEN"

# 读写缓冲：NDJSON 只按行读，小缓冲即可。
_SOCK_BUFSIZE = 64 * 1024


def _endpoint() -> Optional[tuple[str, int, str]]:
    """从环境变量读取 RPC endpoint 三元组，缺失任一项返回 None。"""
    host = os.environ.get(ENV_RPC_HOST)
    port = os.environ.get(ENV_RPC_PORT)
    token = os.environ.get(ENV_RPC_TOKEN)
    if not host or not port or not token:
        return None
    try:
        port_i = int(port)
    except ValueError as exc:
        raise RpcError(f"invalid {ENV_RPC_PORT}: {port}") from exc
    return (host, port_i, token)


class _Connection:
    """单连接封装：握手 + 单 id 计数器 + 线程串行收发。"""

    def __init__(self, host: str, port: int, token: str) -> None:
        self._host = host
        self._port = port
        self._token = token
        self._lock = threading.Lock()
        self._sock: Optional[socket.socket] = None
        self._rfile = None
        self._wfile = None
        self._next_id = 1

    def close(self) -> None:
        with self._lock:
            self._close_locked()

    def _close_locked(self) -> None:
        try:
            if self._rfile is not None:
                self._rfile.close()
            if self._wfile is not None:
                self._wfile.close()
        except OSError:
            pass
        try:
            if self._sock is not None:
                self._sock.close()
        except OSError:
            pass
        self._sock = None
        self._rfile = None
        self._wfile = None

    def _connect_locked(self) -> None:
        sock = socket.create_connection((self._host, self._port), timeout=30.0)
        # 连接建立后取消超时，切回纯阻塞模式，避免长时间执行的工具调用被误杀。
        sock.settimeout(None)
        sock.setsockopt(socket.IPPROTO_TCP, socket.TCP_NODELAY, 1)
        rfile = sock.makefile("rb", buffering=_SOCK_BUFSIZE)
        wfile = sock.makefile("wb", buffering=0)  # 立即刷出，不再依赖 flush 时机

        # 握手
        hello = {"type": "hello", "token": self._token}
        wfile.write((json.dumps(hello, ensure_ascii=False) + "\n").encode("utf-8"))
        line = rfile.readline()
        if not line:
            sock.close()
            raise RpcError("RPC handshake failed: server closed before welcome")
        try:
            resp = json.loads(line.decode("utf-8"))
        except ValueError as e:
            sock.close()
            raise RpcError(f"RPC handshake: invalid welcome json: {e}") from e
        if resp.get("type") != "welcome":
            sock.close()
            raise RpcError(f"RPC handshake: unexpected welcome: {resp!r}")

        self._sock = sock
        self._rfile = rfile
        self._wfile = wfile

    def call(self, method: str, params: Any) -> Any:
        with self._lock:
            if self._sock is None:
                self._connect_locked()
            assert self._rfile is not None and self._wfile is not None  # for type-checker

            req_id = self._next_id
            self._next_id += 1
            frame = {"id": req_id, "method": method, "params": params}
            try:
                self._wfile.write(
                    (json.dumps(frame, ensure_ascii=False) + "\n").encode("utf-8")
                )
            except OSError as e:
                self._close_locked()
                raise RpcError(f"RPC write failed: {e}") from e

            line = self._rfile.readline()
            if not line:
                self._close_locked()
                raise RpcError("RPC read failed: connection closed")
            try:
                resp = json.loads(line.decode("utf-8"))
            except ValueError as e:
                self._close_locked()
                raise RpcError(f"RPC response: invalid json: {e}") from e

            # id 必须与请求相同（PR3 单连接串行，不存在乱序）
            if resp.get("id") != req_id:
                self._close_locked()
                raise RpcError(
                    f"RPC response id mismatch: expected {req_id}, got {resp.get('id')!r}"
                )
            if "error" in resp and resp["error"] is not None:
                err = resp["error"]
                code = err.get("code")
                message = err.get("message", "")
                raise RpcError(f"RPC error {code}: {message}")
            return resp.get("result")


_conn_lock = threading.Lock()
_conn: Optional[_Connection] = None


def _get_conn() -> _Connection:
    global _conn
    ep = _endpoint()
    if ep is None:
        raise RpcError(
            "RPC endpoint not configured: "
            f"{ENV_RPC_HOST}/{ENV_RPC_PORT}/{ENV_RPC_TOKEN} 未注入（非 python_tool 环境?）"
        )
    with _conn_lock:
        if _conn is None:
            _conn = _Connection(*ep)
        return _conn


def call(method: str, params: Any) -> Any:
    """阻塞式 RPC 调用。抛 :class:`RpcError`。"""
    conn = _get_conn()
    return conn.call(method, params)


def _reset_for_tests() -> None:
    """测试辅助：关闭并丢弃当前单例连接。"""
    global _conn
    with _conn_lock:
        if _conn is not None:
            _conn.close()
            _conn = None
